   184	        actor_can_delete: false,
   185	        event_id: random_id("event_request_withdrawn")?,
   186	        refund_ledger_entry_id,
   187	        now_unix: unix_now()?,
   188	    })?;
   189	    delete_request_ref_from_store(&state, &owner, &repo_name, &request_ref)?;
