   594	fn request_mergeability(
   595	    request: &Request,
   596	    access: RepositoryAccess,
   597	    current_main_oid: Option<String>,
   598	) -> RequestMergeabilityResponse {
   599	    let (status, reason) = if matches!(
   600	        request.state,
   601	        RequestState::Resolved | RequestState::Withdrawn
   602	    ) {
   603	        (
   604	            RequestMergeabilityStatus::Closed,
   605	            Some("request is closed".to_string()),
   606	        )
   607	    } else if !matches!(
   608	        access.actor,
   609	        RepositoryActor::Owner | RepositoryActor::Member
   610	    ) {
   611	        (
   612	            RequestMergeabilityStatus::NotMaintainer,
   613	            Some("repo maintainer required".to_string()),
   614	        )
   615	    } else if request.state == RequestState::Working {
   616	        (
   617	            RequestMergeabilityStatus::NotReady,
   618	            Some("request has not been submitted".to_string()),
   619	        )
   620	    } else if request.state == RequestState::NeedsResponse {
   621	        (
   622	            RequestMergeabilityStatus::NotReady,
   623	            Some("request is waiting on contributor response".to_string()),
   624	        )
   625	    } else if request.git_snapshot.is_none() {
   626	        (
   627	            RequestMergeabilityStatus::MissingRequestBranch,
   628	            Some("request branch has not been pushed".to_string()),
   629	        )
   630	    } else {
   631	        (RequestMergeabilityStatus::Ready, None)
   632	    };
   633	    RequestMergeabilityResponse {
   634	        status,
   635	        current_main_oid,
   636	        request_head_oid: request.head_oid.clone(),
   637	        reason,
   638	    }
   639	}
