   504	        return Err(CatalogError::InvalidRepositoryName(
   505	            "repository name cannot be . or ..".to_string(),
   506	        ));
   507	    }
   508	    if name.len() > 80 {
   509	        return Err(CatalogError::InvalidRepositoryName(
   510	            "repository name must be 80 characters or fewer".to_string(),
   511	        ));
   512	    }
   513	    if !name
   514	        .bytes()
   515	        .all(|byte| byte.is_ascii_alphanumeric() || matches!(byte, b'.' | b'-' | b'_'))
   516	    {
   517	        return Err(CatalogError::InvalidRepositoryName(
   518	            "repository name can only use letters, numbers, dots, dashes, or underscores"
   519	                .to_string(),
   520	        ));
   521	    }
   522	
