    77	pub fn accept_repository_invite(
    78	    repo: &mut StoredRepository,
    79	    user: &UserAccount,
    80	    token_hash: &str,
    81	    now_unix: u64,
    82	) -> Result<AcceptRepositoryInviteOutcome, ApiError> {
    83	    let normalized_user_email = normalize_repository_invite_email(&user.email);
    84	    if repo.is_owner_user(&user.id) || repo.member_for_user(&user.id).is_some() {
    85	        return Err(ApiError::conflict("user is already a repository member"));
    86	    }
