    88	        .invitations
    89	        .iter_mut()
    90	        .find(|invite| invite.token_hash == token_hash)
    91	        .ok_or_else(|| ApiError::not_found("repository invite not found"))?;
    92	    if invite.state != RepositoryInviteState::Pending {
    93	        return Err(ApiError::conflict("repository invite is no longer pending"));
    94	    }
    95	    if now_unix >= invite.expires_at_unix {
    96	        invite.state = RepositoryInviteState::Expired;
    97	        invite.updated_at_unix = now_unix;
    98	        repo.bump_change_version();
    99	        return Ok(AcceptRepositoryInviteOutcome::Expired);
   100	    }
   101	    if !user.email_verified || normalized_user_email != invite.invited_email_normalized {
   102	        return Err(ApiError::forbidden(
   103	            "sign in with the verified invited email to accept this invite",
   104	        ));
   105	    }
   106	    invite.state = RepositoryInviteState::Accepted;
   107	    invite.accepted_by_user_id = Some(user.id.clone());
   108	    invite.accepted_at_unix = Some(now_unix);
   109	    invite.updated_at_unix = now_unix;
   110	    let member = RepositoryMember {
   111	        repo_id: repo.record.id.clone(),
   112	        user_id: user.id.clone(),
   113	        permissions: invite.permissions,
   114	        created_at_unix: now_unix,
   115	        updated_at_unix: now_unix,
   116	    };
   117	    repo.members.push(member.clone());
   118	    sort_members(repo);
   119	    repo.bump_change_version();
   120	    Ok(AcceptRepositoryInviteOutcome::Accepted(member))
   121	}
