   136	    pub fn read<R>(
   137	        &self,
   138	        op: impl FnOnce(&AppCatalog) -> Result<R, ApiError>,
   139	    ) -> Result<R, ApiError>
   140	    where
   141	        R: Send + 'static,
   142	    {
   143	        match self.inner.as_ref() {
   144	            MetadataStoreInner::Postgres { db, runtime } => {
   145	                let catalog = load_catalog(runtime, db)?;
   146	                op(&catalog)
   147	            }
   148	            #[cfg(any(test, feature = "memory-metadata"))]
   149	            MetadataStoreInner::Memory(catalog) => {
   150	                let catalog = catalog
   151	                    .catalog
   152	                    .lock()
   153	                    .map_err(|_| ApiError::internal_message("catalog lock is poisoned"))?;
   154	                op(&catalog)
   155	            }
   156	        }
   157	    }
   158	
   159	    #[cfg(any(test, feature = "memory-metadata"))]
   160	    pub fn update<R, F>(&self, op: F) -> Result<R, ApiError>
   161	    where
   162	        R: Send + 'static,
   163	        F: FnOnce(&mut AppCatalog) -> Result<R, ApiError> + Send + 'static,
   164	    {
   165	        match self.inner.as_ref() {
   166	            MetadataStoreInner::Memory(memory) => {
   167	                let mut catalog = memory
   168	                    .catalog
   169	                    .lock()
   170	                    .map_err(|_| ApiError::internal_message("catalog lock is poisoned"))?;
   171	                let mut draft = catalog.clone();
   172	                let result = op(&mut draft)?;
   173	                #[cfg(any(test, feature = "test-support"))]
   174	                {
   175	                    if memory.fail_next_persist.swap(false, Ordering::SeqCst) {
   176	                        return Err(ApiError::internal_message("test metadata persist failure"));
   177	                    }
   178	                }
   179	                *catalog = draft;
   180	                Ok(result)
   181	            }
   182	            MetadataStoreInner::Postgres { .. } => Err(ApiError::internal_message(
   183	                "catalog updates are only available for memory metadata stores",
   184	            )),
   185	        }
   186	    }
