   188	    pub fn repository(
   189	        &self,
   190	        owner: &str,
   191	        name: &str,
   192	    ) -> Result<Option<StoredRepository>, ApiError> {
   193	        let id = repo_id(owner, name);
   194	        match self.inner.as_ref() {
   195	            MetadataStoreInner::Postgres { db, runtime } => {
   196	                let db = Arc::clone(db);
   197	                run_api_db_on(runtime, async move {
   198	                    let tx = begin_metadata_read_snapshot(db.as_ref()).await?;
   199	                    let repo = match entities::repository::Entity::find_by_id(id)
   200	                        .one(&tx)
   201	                        .await
   202	                        .map_err(ApiError::internal)?
   203	                    {
   204	                        Some(repo) => Some(repository_from_model(&tx, repo).await?),
   205	                        None => None,
   206	                    };
   207	                    tx.commit().await.map_err(ApiError::internal)?;
   208	                    Ok(repo)
   209	                })
   210	            }
   211	            #[cfg(any(test, feature = "memory-metadata"))]
   212	            MetadataStoreInner::Memory(catalog) => {
   213	                let catalog = catalog
   214	                    .catalog
   215	                    .lock()
   216	                    .map_err(|_| ApiError::internal_message("catalog lock is poisoned"))?;
   217	                Ok(catalog.repositories.get(&id).cloned())
   218	            }
   219	        }
   220	    }
   280	            }
   281	        }
   282	    }
