   284	    pub fn reset_catalog(&self, reason: &str) -> Result<MetadataResetEvent, ApiError> {
   285	        let event = new_operator_metadata_reset_event(reason);
   286	        match self.inner.as_ref() {
   287	            MetadataStoreInner::Postgres { db, runtime } => {
   288	                let db = Arc::clone(db);
   289	                let event_to_insert = event.clone();
   290	                run_api_db_on(runtime, async move {
   291	                    schema::reset_metadata_schema(db.as_ref())
   292	                        .await
   293	                        .map_err(ApiError::internal)?;
   294	                    schema::migrate_metadata_schema(db.as_ref())
   295	                        .await
   296	                        .map_err(ApiError::internal)?;
   297	                    ensure_metadata_lock_row(db.as_ref())
   298	                        .await
   299	                        .map_err(ApiError::internal)?;
   300	                    insert_metadata_reset_event(db.as_ref(), &event_to_insert)
   301	                        .await
   302	                        .map_err(ApiError::internal)?;
   303	                    Ok(())
   304	                })?;
   305	            }
   306	            #[cfg(any(test, feature = "memory-metadata"))]
   307	            MetadataStoreInner::Memory(memory) => {
   308	                *memory
   309	                    .catalog
   310	                    .lock()
   311	                    .map_err(|_| ApiError::internal_message("catalog lock is poisoned"))? =
   312	                    AppCatalog::default();
   313	                *memory
   314	                    .auth
   315	                    .lock()
   316	                    .map_err(|_| ApiError::internal_message("auth lock is poisoned"))? =
   317	                    auth::MemoryAuthState::default();
   318	                memory
   319	                    .reset_events
   320	                    .lock()
   321	                    .map_err(|_| ApiError::internal_message("reset event lock is poisoned"))?
   322	                    .push(event.clone());
   323	            }
   324	        }
   325	        Ok(event)
   326	    }
