   355	fn connect_postgres_store(database_url: String) -> anyhow::Result<MetadataStore> {
   356	    let database_url = Arc::<str>::from(database_url);
   357	    let runtime = DbRuntime::new()?;
   358	    let connect_database_url = database_url.to_string();
   359	    let db = run_db_on(&runtime, async move {
   360	        let db = Database::connect(&connect_database_url).await?;
   361	        schema::migrate_metadata_schema(&db).await?;
   362	        ensure_metadata_lock_row(&db).await?;
   363	        reset_stale_pre_alpha_metadata(&db).await?;
   364	        Ok::<_, sea_orm::DbErr>(db)
   365	    })?;
   366	
   367	    Ok(MetadataStore {
   368	        inner: Arc::new(MetadataStoreInner::Postgres {
   369	            db: Arc::new(db),
   370	            runtime,
   371	        }),
   372	        postgres_database_url: Some(database_url),
   373	    })
   374	}
