   376	fn connect_postgres_worker_store_with_schema_wait(
   377	    database_url: String,
   378	    wait_timeout: Duration,
   379	    retry_interval: Duration,
   380	) -> anyhow::Result<MetadataStore> {
   381	    let database_url = Arc::<str>::from(database_url);
   382	    let runtime = DbRuntime::new()?;
   383	    let connect_database_url = database_url.to_string();
   384	    let db = run_db_on(&runtime, async move {
   385	        let started = tokio::time::Instant::now();
   386	        loop {
   387	            match connect_worker_database_once(&connect_database_url).await {
   388	                Ok(db) => return Ok(db),
   389	                Err(error) if started.elapsed() < wait_timeout => {
   390	                    tracing::warn!(
   391	                        error = %error,
   392	                        retry_in_secs = retry_interval.as_secs_f64(),
   393	                        "metadata schema is not ready for worker; waiting for API migrations"
   394	                    );
   395	                    tokio::time::sleep(retry_interval).await;
   396	                }
   397	                Err(error) => return Err(error),
   398	            }
   399	        }
   400	    })?;
   401	
   402	    Ok(MetadataStore {
   403	        inner: Arc::new(MetadataStoreInner::Postgres {
   404	            db: Arc::new(db),
   405	            runtime,
   406	        }),
   407	        postgres_database_url: Some(database_url),
   408	    })
   409	}
