   419	fn load_catalog(
   420	    runtime: &tokio::runtime::Runtime,
   421	    db: &Arc<DatabaseConnection>,
   422	) -> Result<AppCatalog, ApiError> {
   423	    let db = Arc::clone(db);
   424	    run_api_db_on(runtime, async move {
   425	        let tx = db.as_ref().begin().await.map_err(ApiError::internal)?;
   426	        acquire_metadata_read_lock(&tx).await?;
   427	        let catalog = load_catalog_async(&tx).await?;
   428	        tx.commit().await.map_err(ApiError::internal)?;
   429	        Ok(catalog)
   430	    })
   431	}
