   444	async fn load_catalog_async<C>(conn: &C) -> Result<AppCatalog, ApiError>
   445	where
   446	    C: ConnectionTrait,
   447	{
   448	    let users = entities::user::Entity::find()
   449	        .order_by_asc(entities::user::Column::Id)
   450	        .all(conn)
   451	        .await
   452	        .map_err(ApiError::internal)?;
   453	    let repositories = entities::repository::Entity::find()
   454	        .order_by_asc(entities::repository::Column::Id)
   455	        .all(conn)
   456	        .await
   457	        .map_err(ApiError::internal)?;
   458	    let members = entities::repository_member::Entity::find()
   459	        .order_by_asc(entities::repository_member::Column::RepoId)
   460	        .order_by_asc(entities::repository_member::Column::UserId)
   461	        .all(conn)
   462	        .await
   463	        .map_err(ApiError::internal)?;
   464	    let invites = entities::repository_invite::Entity::find()
   465	        .order_by_asc(entities::repository_invite::Column::RepoId)
   466	        .order_by_asc(entities::repository_invite::Column::InvitedEmailNormalized)
   467	        .order_by_asc(entities::repository_invite::Column::Id)
   468	        .all(conn)
   469	        .await
   470	        .map_err(ApiError::internal)?;
   471	    let pending_repo_storage_deletions =
   472	        cleanup_queue::load_pending_repo_storage_deletions(conn).await?;
   473	    let pending_source_blob_deletions =
   474	        cleanup_queue::load_pending_source_blob_deletions(conn).await?;
   475	
   476	    let users = users
   477	        .into_iter()
   478	        .map(|user| Ok((user.id.clone(), user.try_into_domain()?)))
   479	        .collect::<Result<_, ApiError>>()?;
   480	    let members_by_repo = members.into_iter().try_fold(
   481	        std::collections::BTreeMap::<String, Vec<RepositoryMember>>::new(),
   482	        |mut by_repo, member| {
   483	            let repo_id = member.repo_id.clone();
   484	            by_repo
   485	                .entry(repo_id)
   486	                .or_default()
   487	                .push(member.try_into_domain()?);
   488	            Ok::<_, ApiError>(by_repo)
   489	        },
   490	    )?;
   491	    let invites_by_repo = invites.into_iter().try_fold(
   492	        std::collections::BTreeMap::<String, Vec<RepositoryInvite>>::new(),
   493	        |mut by_repo, invite| {
   494	            let repo_id = invite.repo_id.clone();
   495	            by_repo
   496	                .entry(repo_id)
   497	                .or_default()
   498	                .push(invite.try_into_domain()?);
   499	            Ok::<_, ApiError>(by_repo)
   500	        },
   501	    )?;
   502	    let repo_ids = repositories
   503	        .iter()
   504	        .map(|repo| repo.id.clone())
   505	        .collect::<Vec<_>>();
   506	    let mut facts_by_repo = load_repository_facts(conn, &repo_ids).await?;
   507	    let repositories = repositories
   508	        .into_iter()
   509	        .map(|repo| {
   510	            let repo_id = repo.id.clone();
   511	            let members = members_by_repo.get(&repo_id).cloned().unwrap_or_default();
   512	            let invitations = invites_by_repo.get(&repo_id).cloned().unwrap_or_default();
   513	            let facts = facts_by_repo.remove(&repo_id).ok_or_else(|| {
   514	                ApiError::internal_message(format!("repository facts missing for {repo_id}"))
   515	            })?;
   516	            let repo =
   517	                repo.try_into_domain(facts.into_required(&repo_id)?, members, invitations)?;
   518	            Ok((repo.record.id.clone(), repo))
   519	        })
   520	        .collect::<Result<_, ApiError>>()?;
   521	
   522	    let request_rows = load_request_catalog_rows(conn).await?;
   523	
   524	    Ok(AppCatalog {
   525	        users,
   526	        repositories,
   527	        requests: request_rows.requests,
   528	        request_events: request_rows.request_events,
   529	        user_credit_accounts: request_rows.user_credit_accounts,
   530	        credit_ledger_entries: request_rows.credit_ledger_entries,
   531	        pending_repo_storage_deletions,
   532	        pending_source_blob_deletions,
   533	    })
   534	}
